bash #!/usr/bin/env bash set -e echo "Creating project architecture..." mkdir -p docs/canonical mkdir -p docs/branches mkdir -p docs/snapshots mkdir -p docs/templates mkdir -p docs/registry touch docs/canonical/README.md touch docs/branches/README.md touch docs/snapshots/README.md touch docs/templates/README.md touch docs/registry/README.md cat > docs/canonical/README.md <<'EOF' # Canonical Files This folder stores approved project-level documents. Rules: - only approved decisions belong here - no temporary notes - no branch-local reasoning - updates should go through repository control EOF cat > docs/branches/README.md <<'EOF' # Branch Memory Files This folder stores memory files for active, paused, archived, or reloading branches. Path pattern: - /docs/branches/<branch-name>.md Rules: - every stable branch must have a branch memory file - important context must not live only in chat - branch memory must be updated before snapshot and reload EOF cat > docs/snapshots/README.md <<'EOF' # Snapshots This folder stores branch snapshots used for reload, pause, handoff, or cycle-end preservation. Rules: - snapshots are immutable records - snapshots must reference the source branch - snapshots should contain restart-safe compressed context EOF cat > docs/templates/README.md <<'EOF' # Templates This folder stores reusable templates for branch memory files, snapshot files, handoff blocks, and change requests. EOF cat > docs/registry/README.md <<'EOF' # Registry This folder stores registries for branches, canonical files, and repository governance indexes. EOF cat > docs/registry/branch-registry.md <<'EOF' # BRANCH REGISTRY ## Active Branches ## Paused Branches ## Archived Branches ## Reloading Branches EOF cat > docs/templates/branch-memory-template.md <<'EOF' # BRANCH MEMORY FILE ## 1. Branch Identity - Branch Name: - Branch ID: - Version: - Status: active | paused | archived | reloading - Owner Role: - Created From: - Last Reload: - Last Updated: --- ## 2. Purpose ### Mission Short statement describing why this branch exists. ### Scope Clear list of what this branch is allowed to work on. ### Out of Scope Clear list of what this branch must not do. --- ## 3. Current Operating Context ### Current Phase - discovery | structuring | validating | documenting | handoff ### Active Objective Single current objective for this branch. ### Current Task The immediate task being worked on right now. ### Success Condition What must be true for the current task to be considered complete. --- ## 4. Dependencies and Interfaces ### Upstream Inputs What this branch receives from other branches or canonical files. ### Downstream Outputs What this branch is expected to produce for others. ### Related Branches - Branch: - Relationship: - Dependency Type: required | optional | advisory ### Canonical Files Referenced List of approved files this branch depends on. --- ## 5. Owned Artifacts ### Working Artifacts List of non-canonical files, notes, drafts, research outputs owned by this branch. ### Proposed Canonical Contributions List of candidate artifacts or sections that may later be promoted. ### Snapshot Location Path to this branch’s snapshot folder. --- ## 6. Canonical Decisions in Force List only approved decisions that this branch must obey. --- ## 7. Working Assumptions --- ## 8. Open Questions --- ## 9. Active Tasks --- ## 10. Recent Decisions Made in Branch --- ## 11. Proposed Change Requests --- ## 12. Risks and Drift Signals --- ## 13. Reload Seed ### Reload Summary ### Continue From ### Must Preserve ### Must Not Recompute ### First Task After Reload --- ## 14. Recent Snapshot Reference --- ## 15. Branch Handoff Format EOF cat > docs/canonical/repository-rules.md <<'EOF' # REPOSITORY RULES ## Purpose Define how the repository stores project memory, canonical truth, and branch-local working state. ## Core Rules 1. Canonical files contain only approved decisions. 2. Branch-local reasoning must stay in branch memory files or working files. 3. Snapshots are used for reload, pause, handoff, and cycle-end preservation. 4. Important context must not exist only in chat. 5. Changes to canonical files should be proposed before being accepted. EOF cat > .gitignore <<'EOF' .DS_Store node_modules/ .next/ .env .env.local EOF echo "Done." echo "" echo "Created:" echo "- docs/canonical" echo "- docs/branches" echo "- docs/snapshots" echo "- docs/templates" echo "- docs/registry" echo "- docs/templates/branch-memory-template.md" echo "- docs/registry/branch-registry.md" echo "- docs/canonical/repository-rules.md"
